import json
import boto3
import os
from datetime import datetime
import logging
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

def lambda_handler(event, context):
    """
    Process user-uploaded images from S3
    """
    
    try:
        for record in event['Records']:
            bucket = record['s3']['bucket']['name']
            key = record['s3']['object']['key']
            
            logger.info(f"Processing file: {key} from bucket: {bucket}")
            
            if not is_valid_image(key):
                logger.warning(f"Skipping non-image file: {key}")
                continue
            
            image_data = read_image_from_s3(bucket, key)
            
            if image_data is None:
                logger.error(f"Failed to read image: {key}")
                continue
            
            processed_result = process_image(image_data, key)
            
            result_key = generate_result_key(key)
            write_result_to_s3(
                os.environ.get('RESULTS_BUCKET', bucket),
                result_key,
                processed_result
            )
            
            send_notification(key, result_key, processed_result)
            
            logger.info(f"Successfully processed: {key}")
        
        return {
            'statusCode': 200,
            'body': json.dumps('Processing completed successfully')
        }
        
    except Exception as e:
        logger.error(f"Error processing images: {str(e)}", exc_info=True)
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error: {str(e)}')
        }


def is_valid_image(key):
    """
    Validate that the file is an image based on extension
    """
    valid_extensions = ['.jpg', '.jpeg', '.png', '.gif', '.bmp', '.webp']
    return any(key.lower().endswith(ext) for ext in valid_extensions)


def read_image_from_s3(bucket, key):
    """
    Read image from S3 bucket with size validation
    """
    try:
        max_size = int(os.environ.get('MAX_IMAGE_SIZE_MB', '10')) * 1024 * 1024
        
        head_response = s3_client.head_object(Bucket=bucket, Key=key)
        content_length = head_response.get('ContentLength', 0)
        
        if content_length > max_size:
            logger.error(f"Image {key} exceeds maximum size: {content_length} bytes")
            return None
        
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response['Body'].read()
        
        logger.info(f"Read {len(image_data)} bytes from {bucket}/{key}")
        return image_data
        
    except ClientError as e:
        logger.error(f"Error reading from S3: {str(e)}")
        return None


def process_image(image_data, filename):
    """
    Process the image - placeholder for actual image processing logic
    """
    result = {
        'filename': filename,
        'size': len(image_data),
        'processed_at': datetime.utcnow().isoformat(),
        'status': 'processed'
    }
    
    logger.info(f"Processed image: {filename}, size: {len(image_data)} bytes")
    return result


def generate_result_key(original_key):
    """
    Generate S3 key for processed result
    """
    timestamp = datetime.utcnow().strftime('%Y%m%d_%H%M%S')
    base_name = os.path.splitext(os.path.basename(original_key))[0]
    sanitized_name = ''.join(c for c in base_name if c.isalnum() or c in ('_', '-'))
    return f"processed/{sanitized_name}_{timestamp}_result.json"


def write_result_to_s3(bucket, key, result):
    """
    Write processing result to S3
    """
    try:
        s3_client.put_object(
            Bucket=bucket,
            Key=key,
            Body=json.dumps(result, indent=2),
            ContentType='application/json',
            ServerSideEncryption='AES256'
        )
        logger.info(f"Wrote result to {bucket}/{key}")
        
    except ClientError as e:
        logger.error(f"Error writing to S3: {str(e)}")
        raise


def send_notification(original_key, result_key, result):
    """
    Send SNS notification about processed image
    """
    try:
        topic_arn = os.environ.get('SNS_TOPIC_ARN')
        
        if not topic_arn:
            logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
            return
        
        message = {
            'original_file': original_key,
            'result_file': result_key,
            'status': result.get('status'),
            'processed_at': result.get('processed_at')
        }
        
        sns_client.publish(
            TopicArn=topic_arn,
            Subject=f'Image Processing Complete: {os.path.basename(original_key)}',
            Message=json.dumps(message, indent=2)
        )
        
        logger.info(f"Sent notification for {original_key}")
        
    except ClientError as e:
        logger.error(f"Error sending SNS notification: {str(e)}")


